head.b:skin:
/**
 * AiCoN Blog Theme - Blogger XML Version
 * Premium Modern UI inspired by PixelOS, Material Design 3, and Linear.app
 * Version: 1.0.0
 */

/* ============================================
   CSS CUSTOM PROPERTIES (Design Tokens)
   ============================================ */

:root {
  /* Light Theme Colors */
  --color-background: #fafbfc;
  --color-surface: #ffffff;
  --color-surface-secondary: #f4f5f7;
  --color-surface-tertiary: #ebecf0;
  --color-surface-hover: #f0f1f3;

  --color-text-primary: #1a1d21;
  --color-text-secondary: #5e6368;
  --color-text-tertiary: #80868b;
  --color-text-inverse: #ffffff;

  --color-accent: #0066ff;
  --color-accent-hover: #0052cc;
  --color-accent-light: rgba(0, 102, 255, 0.1);
  --color-accent-gradient: linear-gradient(135deg, #0066ff 0%, #00d4ff 100%);

  --color-success: #00c853;
  --color-warning: #ff9100;
  --color-error: #ff3d00;

  --color-border: #e4e7eb;
  --color-border-light: #f0f1f3;
  --color-divider: rgba(0, 0, 0, 0.06);

  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.04);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.06);
  --shadow-lg: 0 8px 30px rgba(0, 0, 0, 0.08);
  --shadow-xl: 0 20px 60px rgba(0, 0, 0, 0.1);
  --shadow-glow: 0 0 40px rgba(0, 102, 255, 0.15);

  /* Typography Scale */
  --font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;

  --text-hero: clamp(3rem, 8vw, 5rem);
  --text-h1: clamp(2rem, 5vw, 3rem);
  --text-h2: clamp(1.5rem, 3vw, 2rem);
  --text-h3: clamp(1.25rem, 2vw, 1.5rem);
  --text-body: 1rem;
  --text-small: 0.875rem;
  --text-caption: 0.75rem;

  --leading-tight: 1.2;
  --leading-normal: 1.6;
  --leading-relaxed: 1.8;

  --tracking-tight: -0.02em;
  --tracking-normal: 0;
  --tracking-wide: 0.02em;

  /* Spacing */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 16px;
  --space-lg: 24px;
  --space-xl: 32px;
  --space-2xl: 48px;
  --space-3xl: 64px;
  --space-4xl: 96px;
  --space-section: 120px;

  /* Layout */
  --container-max: 1280px;
  --content-max: 720px;
  --sidebar-width: 320px;
  --nav-height: 72px;

  /* Border Radius */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --radius-2xl: 32px;
  --radius-full: 9999px;

  /* Transitions */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out: cubic-bezier(0.65, 0, 0.35, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);

  --duration-fast: 150ms;
  --duration-normal: 250ms;
  --duration-slow: 400ms;
  --duration-slower: 600ms;

  /* Z-Index Scale */
  --z-base: 1;
  --z-dropdown: 100;
  --z-sticky: 200;
  --z-overlay: 300;
  --z-modal: 400;
  --z-toast: 500;
}

/* Dark Theme */
[data-theme="dark"] {
  --color-background: #0a0a0f;
  --color-surface: #141419;
  --color-surface-secondary: #1c1c24;
  --color-surface-tertiary: #252530;
  --color-surface-hover: #1f1f2a;

  --color-text-primary: #ffffff;
  --color-text-secondary: #a0a0b0;
  --color-text-tertiary: #6b6b7b;
  --color-text-inverse: #0a0a0f;

  --color-accent: #4d9fff;
  --color-accent-hover: #66aaff;
  --color-accent-light: rgba(77, 159, 255, 0.15);
  --color-accent-gradient: linear-gradient(135deg, #4d9fff 0%, #00d4ff 100%);

  --color-border: rgba(255, 255, 255, 0.08);
  --color-border-light: rgba(255, 255, 255, 0.04);
  --color-divider: rgba(255, 255, 255, 0.06);

  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.2);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 8px 30px rgba(0, 0, 0, 0.4);
  --shadow-xl: 0 20px 60px rgba(0, 0, 0, 0.5);
  --shadow-glow: 0 0 40px rgba(77, 159, 255, 0.2);
}

/* ============================================
   CSS RESET & BASE STYLES
   ============================================ */

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

body {
  font-family: var(--font-family);
  font-size: var(--text-body);
  line-height: var(--leading-normal);
  color: var(--color-text-primary);
  background-color: var(--color-background);
  overflow-x: hidden;
  min-height: 100vh;
  transition: background-color var(--duration-normal) var(--ease-out),
              color var(--duration-normal) var(--ease-out);
}

::selection {
  background-color: var(--color-accent-light);
  color: var(--color-accent);
}

a {
  color: inherit;
  text-decoration: none;
  transition: color var(--duration-fast) var(--ease-out);
}

a:hover {
  color: var(--color-accent);
}

img, svg {
  display: block;
  max-width: 100%;
  height: auto;
}

button {
  font-family: inherit;
  font-size: inherit;
  border: none;
  background: none;
  cursor: pointer;
  color: inherit;
}

ul, ol {
  list-style: none;
}

:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: var(--color-surface);
}

::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: var(--radius-full);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-tertiary);
}

/* ============================================
   LAYOUT UTILITIES
   ============================================ */

.container {
  width: 100%;
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 0 var(--space-lg);
}

.container--narrow {
  max-width: var(--content-max);
}

.section {
  padding: var(--space-section) 0;
}

.section--tight {
  padding: var(--space-3xl) 0;
}

/* ============================================
   TYPOGRAPHY
   ============================================ */

.text-hero {
  font-size: var(--text-hero);
  font-weight: 600;
  line-height: var(--leading-tight);
  letter-spacing: var(--tracking-tight);
}

.text-h1 {
  font-size: var(--text-h1);
  font-weight: 600;
  line-height: var(--leading-tight);
  letter-spacing: var(--tracking-tight);
}

.text-h2 {
  font-size: var(--text-h2);
  font-weight: 600;
  line-height: var(--leading-tight);
}

.text-h3 {
  font-size: var(--text-h3);
  font-weight: 500;
  line-height: var(--leading-tight);
}

.text-gradient {
  background: var(--color-accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ============================================
   NAVBAR
   ============================================ */

.navbar {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: var(--nav-height);
  z-index: var(--z-sticky);
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--color-border-light);
  transition: all var(--duration-normal) var(--ease-out);
}

[data-theme="dark"] .navbar {
  background: rgba(10, 10, 15, 0.85);
}

.navbar.scrolled {
  box-shadow: var(--shadow-md);
}

.navbar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 100%;
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 0 var(--space-lg);
}

.navbar__logo {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  font-weight: 600;
  font-size: var(--text-h3);
  transition: transform var(--duration-fast) var(--ease-out);
}

.navbar__logo:hover {
  transform: scale(1.02);
  color: inherit;
}

.navbar__logo-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  background: var(--color-accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 700;
  font-size: 18px;
}

.navbar__nav {
  display: flex;
  align-items: center;
  gap: var(--space-xl);
}

.navbar__link {
  position: relative;
  font-weight: 500;
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  padding: var(--space-sm) 0;
  transition: color var(--duration-fast) var(--ease-out);
}

.navbar__link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--color-accent);
  border-radius: var(--radius-full);
  transition: width var(--duration-normal) var(--ease-out);
}

.navbar__link:hover,
.navbar__link.active {
  color: var(--color-text-primary);
}

.navbar__link:hover::after,
.navbar__link.active::after {
  width: 100%;
}

.navbar__actions {
  display: flex;
  align-items: center;
  gap: var(--space-md);
}

/* Theme Toggle */
.theme-toggle {
  width: 44px;
  height: 44px;
  border-radius: var(--radius-lg);
  background: var(--color-surface-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--duration-normal) var(--ease-out);
  cursor: pointer;
  border: none;
}

.theme-toggle:hover {
  background: var(--color-surface-tertiary);
  transform: scale(1.05);
}

.theme-toggle svg {
  width: 22px;
  height: 22px;
  color: var(--color-text-secondary);
  transition: transform var(--duration-normal) var(--ease-spring);
}

.theme-toggle:hover svg {
  transform: rotate(15deg);
}

[data-theme="dark"] .theme-toggle .icon-sun { display: block; }
[data-theme="dark"] .theme-toggle .icon-moon { display: none; }
:not([data-theme="dark"]) .theme-toggle .icon-sun { display: none; }
:not([data-theme="dark"]) .theme-toggle .icon-moon { display: block; }

/* Search Button */
.search-toggle {
  width: 44px;
  height: 44px;
  border-radius: var(--radius-lg);
  background: var(--color-surface-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--duration-normal) var(--ease-out);
  cursor: pointer;
  border: none;
}

.search-toggle:hover {
  background: var(--color-surface-tertiary);
  transform: scale(1.05);
}

.search-toggle svg {
  width: 20px;
  height: 20px;
  color: var(--color-text-secondary);
}

/* Mobile Menu Toggle */
.menu-toggle {
  display: none;
  width: 44px;
  height: 44px;
  border-radius: var(--radius-lg);
  background: var(--color-surface-secondary);
  align-items: center;
  justify-content: center;
  transition: all var(--duration-normal) var(--ease-out);
  cursor: pointer;
  border: none;
}

.menu-toggle:hover {
  background: var(--color-surface-tertiary);
}

.menu-toggle__line {
  width: 20px;
  height: 2px;
  background: var(--color-text-primary);
  border-radius: var(--radius-full);
  position: relative;
  transition: all var(--duration-normal) var(--ease-out);
}

.menu-toggle__line::before,
.menu-toggle__line::after {
  content: '';
  position: absolute;
  left: 0;
  width: 100%;
  height: 2px;
  background: var(--color-text-primary);
  border-radius: var(--radius-full);
  transition: all var(--duration-normal) var(--ease-out);
}

.menu-toggle__line::before { top: -6px; }
.menu-toggle__line::after { top: 6px; }

.menu-toggle.active .menu-toggle__line {
  background: transparent;
}

.menu-toggle.active .menu-toggle__line::before {
  top: 0;
  transform: rotate(45deg);
}

.menu-toggle.active .menu-toggle__line::after {
  top: 0;
  transform: rotate(-45deg);
}

/* ============================================
   FULLSCREEN MENU
   ============================================ */

.menu-overlay {
  position: fixed;
  inset: 0;
  background: var(--color-background);
  z-index: var(--z-overlay);
  opacity: 0;
  visibility: hidden;
  transition: all var(--duration-slow) var(--ease-out);
  overflow-y: auto;
  padding: var(--nav-height) 0 var(--space-3xl);
}

.menu-overlay.active {
  opacity: 1;
  visibility: visible;
}

.menu-overlay__inner {
  max-width: var(--container-max);
  margin: 0 auto;
  padding: var(--space-3xl) var(--space-lg);
}

.menu-overlay__item {
  opacity: 0;
  transform: translateY(30px);
  transition: all var(--duration-slow) var(--ease-out);
}

.menu-overlay.active .menu-overlay__item {
  opacity: 1;
  transform: translateY(0);
}

.menu-overlay.active .menu-overlay__item:nth-child(1) { transition-delay: 0.1s; }
.menu-overlay.active .menu-overlay__item:nth-child(2) { transition-delay: 0.15s; }
.menu-overlay.active .menu-overlay__item:nth-child(3) { transition-delay: 0.2s; }
.menu-overlay.active .menu-overlay__item:nth-child(4) { transition-delay: 0.25s; }
.menu-overlay.active .menu-overlay__item:nth-child(5) { transition-delay: 0.3s; }
.menu-overlay.active .menu-overlay__item:nth-child(6) { transition-delay: 0.35s; }
.menu-overlay.active .menu-overlay__item:nth-child(7) { transition-delay: 0.4s; }

.menu-overlay__link {
  display: block;
  font-size: clamp(2rem, 5vw, 3.5rem);
  font-weight: 600;
  color: var(--color-text-primary);
  padding: var(--space-md) 0;
  border-bottom: 1px solid var(--color-border-light);
  transition: all var(--duration-normal) var(--ease-out);
}

.menu-overlay__link:hover {
  color: var(--color-accent);
  padding-left: var(--space-lg);
  text-decoration: none;
}

/* ============================================
   HERO SECTION
   ============================================ */

.hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding-top: var(--nav-height);
  position: relative;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  width: 150%;
  height: 80%;
  background: radial-gradient(ellipse at center top, var(--color-accent-light) 0%, transparent 70%);
  transform: translateX(-50%);
  opacity: 0.6;
  pointer-events: none;
}

.hero__inner {
  position: relative;
  z-index: 1;
  text-align: center;
  max-width: 900px;
  margin: 0 auto;
  padding: var(--space-4xl) var(--space-lg);
}

.hero__badge {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm) var(--space-md);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  font-size: var(--text-small);
  font-weight: 500;
  color: var(--color-text-secondary);
  margin-bottom: var(--space-xl);
  box-shadow: var(--shadow-sm);
  animation: fadeInUp 0.8s var(--ease-out) 0.2s both;
}

.hero__badge-dot {
  width: 8px;
  height: 8px;
  background: var(--color-success);
  border-radius: var(--radius-full);
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.6; transform: scale(1.2); }
}

.hero__title {
  font-size: var(--text-hero);
  font-weight: 600;
  line-height: var(--leading-tight);
  letter-spacing: var(--tracking-tight);
  margin-bottom: var(--space-lg);
  animation: fadeInUp 0.8s var(--ease-out) 0.3s both;
}

.hero__subtitle {
  font-size: clamp(1rem, 2vw, 1.25rem);
  color: var(--color-text-secondary);
  max-width: 600px;
  margin: 0 auto var(--space-xl);
  line-height: var(--leading-relaxed);
  animation: fadeInUp 0.8s var(--ease-out) 0.4s both;
}

.hero__actions {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-md);
  flex-wrap: wrap;
  animation: fadeInUp 0.8s var(--ease-out) 0.5s both;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.hero__scroll {
  position: absolute;
  bottom: var(--space-xl);
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-sm);
  color: var(--color-text-tertiary);
  font-size: var(--text-caption);
  animation: bounce 2s ease-in-out infinite;
}

@keyframes bounce {
  0%, 100% { transform: translateX(-50%) translateY(0); }
  50% { transform: translateX(-50%) translateY(10px); }
}

/* ============================================
   BUTTONS
   ============================================ */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-sm);
  padding: 14px 28px;
  font-weight: 500;
  font-size: var(--text-small);
  border-radius: var(--radius-full);
  transition: all var(--duration-normal) var(--ease-out);
  position: relative;
  overflow: hidden;
  min-height: 48px;
  cursor: pointer;
  border: none;
}

.btn--primary {
  background: var(--color-accent-gradient);
  color: white;
  box-shadow: 0 4px 20px rgba(0, 102, 255, 0.3);
}

.btn--primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 30px rgba(0, 102, 255, 0.4);
  color: white;
  text-decoration: none;
}

.btn--primary:active {
  transform: translateY(0);
}

.btn--secondary {
  background: var(--color-surface);
  color: var(--color-text-primary);
  border: 1px solid var(--color-border);
}

.btn--secondary:hover {
  background: var(--color-surface-secondary);
  border-color: var(--color-accent);
  color: var(--color-accent);
  transform: translateY(-2px);
  text-decoration: none;
}

.btn__ripple {
  position: absolute;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.4);
  transform: scale(0);
  animation: ripple 0.6s linear;
  pointer-events: none;
}

@keyframes ripple {
  to {
    transform: scale(4);
    opacity: 0;
  }
}

/* ============================================
   SECTION HEADERS
   ============================================ */

.section-header {
  text-align: center;
  margin-bottom: var(--space-3xl);
}

.section-header__badge {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  padding: 8px 16px;
  background: var(--color-accent-light);
  border-radius: var(--radius-full);
  font-size: var(--text-caption);
  font-weight: 600;
  color: var(--color-accent);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
  margin-bottom: var(--space-md);
}

.section-header__title {
  font-size: var(--text-h1);
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: var(--space-md);
}

.section-header__subtitle {
  font-size: var(--text-body);
  color: var(--color-text-secondary);
  max-width: 600px;
  margin: 0 auto;
}

/* ============================================
   BLOG POST CARDS
   ============================================ */

.posts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: var(--space-xl);
}

.blog-post {
  background: var(--color-surface);
  border-radius: var(--radius-xl);
  overflow: hidden;
  border: 1px solid var(--color-border-light);
  transition: all var(--duration-normal) var(--ease-out);
  position: relative;
}

.blog-post:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-xl);
  border-color: var(--color-border);
}

.blog-post__image {
  position: relative;
  aspect-ratio: 16 / 10;
  overflow: hidden;
}

.blog-post__image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform var(--duration-slow) var(--ease-out);
}

.blog-post:hover .blog-post__image img {
  transform: scale(1.05);
}

.blog-post__category {
  position: absolute;
  top: var(--space-md);
  left: var(--space-md);
  padding: 6px 14px;
  background: var(--color-surface);
  border-radius: var(--radius-full);
  font-size: var(--text-caption);
  font-weight: 600;
  color: var(--color-accent);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
  box-shadow: var(--shadow-md);
  transition: all var(--duration-normal) var(--ease-out);
}

.blog-post:hover .blog-post__category {
  background: var(--color-accent);
  color: white;
}

.blog-post__content {
  padding: var(--space-lg);
}

.blog-post__meta {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  margin-bottom: var(--space-sm);
  font-size: var(--text-caption);
  color: var(--color-text-tertiary);
}

.blog-post__meta-item {
  display: flex;
  align-items: center;
  gap: 6px;
}

.blog-post__title {
  font-size: var(--text-h3);
  font-weight: 600;
  line-height: var(--leading-tight);
  margin-bottom: var(--space-sm);
  color: var(--color-text-primary);
  transition: color var(--duration-fast) var(--ease-out);
}

.blog-post:hover .blog-post__title {
  color: var(--color-accent);
}

.blog-post__title a {
  color: inherit;
}

.blog-post__title a:hover {
  text-decoration: none;
}

.blog-post__excerpt {
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
  margin-bottom: var(--space-md);
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.blog-post__footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-md);
  border-top: 1px solid var(--color-border-light);
}

.blog-post__author {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

.blog-post__author-avatar {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-full);
  object-fit: cover;
}

.blog-post__author-name {
  font-size: var(--text-small);
  font-weight: 500;
  color: var(--color-text-secondary);
}

.blog-post__link {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  font-size: var(--text-small);
  font-weight: 500;
  color: var(--color-accent);
  transition: all var(--duration-fast) var(--ease-out);
}

.blog-post__link:hover {
  text-decoration: none;
  gap: var(--space-sm);
}

/* ============================================
   FEATURED POST
   ============================================ */

.featured-post {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-xl);
  background: var(--color-surface);
  border-radius: var(--radius-2xl);
  overflow: hidden;
  border: 1px solid var(--color-border-light);
  transition: all var(--duration-normal) var(--ease-out);
}

.featured-post:hover {
  box-shadow: var(--shadow-xl);
  transform: translateY(-4px);
}

.featured-post__image {
  position: relative;
  aspect-ratio: 4 / 3;
  overflow: hidden;
}

.featured-post__image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform var(--duration-slow) var(--ease-out);
}

.featured-post:hover .featured-post__image img {
  transform: scale(1.05);
}

.featured-post__badge {
  position: absolute;
  top: var(--space-lg);
  left: var(--space-lg);
  padding: 8px 16px;
  background: var(--color-accent-gradient);
  color: white;
  font-size: var(--text-caption);
  font-weight: 600;
  border-radius: var(--radius-full);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
}

.featured-post__content {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: var(--space-xl);
}

.featured-post__category {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  font-size: var(--text-caption);
  font-weight: 600;
  color: var(--color-accent);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
  margin-bottom: var(--space-md);
}

.featured-post__title {
  font-size: var(--text-h1);
  font-weight: 600;
  line-height: var(--leading-tight);
  margin-bottom: var(--space-md);
  color: var(--color-text-primary);
}

.featured-post:hover .featured-post__title {
  color: var(--color-accent);
}

.featured-post__title a {
  color: inherit;
}

.featured-post__title a:hover {
  text-decoration: none;
}

.featured-post__excerpt {
  font-size: var(--text-body);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
  margin-bottom: var(--space-lg);
}

.featured-post__meta {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
  font-size: var(--text-small);
  color: var(--color-text-tertiary);
}

/* ============================================
   SINGLE POST PAGE
   ============================================ */

.post-single {
  max-width: var(--content-max);
  margin: 0 auto;
  padding: calc(var(--nav-height) + var(--space-3xl)) var(--space-lg) var(--space-3xl);
}

.post-single__header {
  text-align: center;
  margin-bottom: var(--space-3xl);
}

.post-single__category {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  padding: 8px 16px;
  background: var(--color-accent-light);
  border-radius: var(--radius-full);
  font-size: var(--text-caption);
  font-weight: 600;
  color: var(--color-accent);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
  margin-bottom: var(--space-lg);
}

.post-single__title {
  font-size: var(--text-h1);
  font-weight: 600;
  line-height: var(--leading-tight);
  margin-bottom: var(--space-lg);
  color: var(--color-text-primary);
}

.post-single__meta {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-lg);
  font-size: var(--text-small);
  color: var(--color-text-tertiary);
}

.post-single__meta-item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.post-single__featured-image {
  width: 100%;
  aspect-ratio: 16 / 9;
  object-fit: cover;
  border-radius: var(--radius-xl);
  margin-bottom: var(--space-3xl);
}

.post-single__content {
  font-size: var(--text-body);
  line-height: var(--leading-relaxed);
  color: var(--color-text-secondary);
}

.post-single__content h2 {
  font-size: var(--text-h2);
  font-weight: 600;
  color: var(--color-text-primary);
  margin: var(--space-2xl) 0 var(--space-lg);
}

.post-single__content h3 {
  font-size: var(--text-h3);
  font-weight: 600;
  color: var(--color-text-primary);
  margin: var(--space-xl) 0 var(--space-md);
}

.post-single__content p {
  margin-bottom: var(--space-lg);
}

.post-single__content a {
  color: var(--color-accent);
  text-decoration: underline;
  text-decoration-color: transparent;
  text-underline-offset: 3px;
  transition: text-decoration-color var(--duration-fast) var(--ease-out);
}

.post-single__content a:hover {
  text-decoration-color: var(--color-accent);
}

.post-single__content img {
  max-width: 100%;
  border-radius: var(--radius-lg);
  margin: var(--space-xl) 0;
}

.post-single__content blockquote {
  margin: var(--space-xl) 0;
  padding: var(--space-lg);
  border-left: 4px solid var(--color-accent);
  background: var(--color-surface-secondary);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  font-style: italic;
  color: var(--color-text-primary);
}

.post-single__content code {
  font-family: var(--font-mono);
  font-size: 0.9em;
  background: var(--color-surface-secondary);
  padding: 2px 8px;
  border-radius: var(--radius-sm);
  color: var(--color-accent);
}

.post-single__content pre {
  background: var(--color-surface-secondary);
  padding: var(--space-lg);
  border-radius: var(--radius-lg);
  overflow-x: auto;
  margin: var(--space-xl) 0;
}

.post-single__content pre code {
  background: none;
  padding: 0;
  color: var(--color-text-primary);
}

.post-single__content ul,
.post-single__content ol {
  margin: var(--space-lg) 0;
  padding-left: var(--space-xl);
}

.post-single__content li {
  margin-bottom: var(--space-sm);
  list-style: disc;
}

.post-single__content ol li {
  list-style: decimal;
}

.post-single__tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  margin-top: var(--space-3xl);
  padding-top: var(--space-xl);
  border-top: 1px solid var(--color-border);
}

.post-single__tag {
  padding: 8px 16px;
  background: var(--color-surface-secondary);
  border-radius: var(--radius-full);
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  transition: all var(--duration-fast) var(--ease-out);
}

.post-single__tag:hover {
  background: var(--color-accent);
  color: white;
  text-decoration: none;
}

/* ============================================
   PAGINATION
   ============================================ */

.pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-md);
  padding: var(--space-3xl) 0;
}

.pagination__link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 48px;
  height: 48px;
  padding: 0 var(--space-md);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  font-weight: 500;
  color: var(--color-text-secondary);
  transition: all var(--duration-normal) var(--ease-out);
}

.pagination__link:hover {
  background: var(--color-accent);
  border-color: var(--color-accent);
  color: white;
  text-decoration: none;
  transform: translateY(-2px);
}

.pagination__link--active {
  background: var(--color-accent);
  border-color: var(--color-accent);
  color: white;
}

/* ============================================
   SIDEBAR
   ============================================ */

.sidebar {
  display: flex;
  flex-direction: column;
  gap: var(--space-xl);
}

.sidebar__widget {
  background: var(--color-surface);
  border-radius: var(--radius-xl);
  padding: var(--space-lg);
  border: 1px solid var(--color-border-light);
}

.sidebar__widget-title {
  font-size: var(--text-h3);
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: var(--space-lg);
  padding-bottom: var(--space-md);
  border-bottom: 2px solid var(--color-accent);
}

.sidebar__about {
  text-align: center;
}

.sidebar__about-avatar {
  width: 80px;
  height: 80px;
  border-radius: var(--radius-full);
  margin: 0 auto var(--space-md);
  object-fit: cover;
  border: 3px solid var(--color-accent);
}

.sidebar__about-name {
  font-size: var(--text-body);
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: var(--space-xs);
}

.sidebar__about-bio {
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
}

.sidebar__links {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.sidebar__link {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-sm) var(--space-md);
  background: var(--color-surface-secondary);
  border-radius: var(--radius-md);
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  transition: all var(--duration-fast) var(--ease-out);
}

.sidebar__link:hover {
  background: var(--color-accent);
  color: white;
  text-decoration: none;
  padding-left: var(--space-lg);
}

.sidebar__link-count {
  font-size: var(--text-caption);
  background: var(--color-surface);
  padding: 2px 8px;
  border-radius: var(--radius-full);
}

.sidebar__link:hover .sidebar__link-count {
  background: rgba(255, 255, 255, 0.2);
  color: white;
}

/* ============================================
   NEWSLETTER
   ============================================ */

.newsletter {
  background: var(--color-surface);
  border-radius: var(--radius-2xl);
  padding: var(--space-3xl);
  text-align: center;
  position: relative;
  overflow: hidden;
  border: 1px solid var(--color-border-light);
}

.newsletter::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle at center, var(--color-accent-light) 0%, transparent 50%);
  animation: rotate 20s linear infinite;
}

@keyframes rotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.newsletter__inner {
  position: relative;
  z-index: 1;
  max-width: 500px;
  margin: 0 auto;
}

.newsletter__icon {
  width: 80px;
  height: 80px;
  margin: 0 auto var(--space-lg);
  background: var(--color-accent-gradient);
  border-radius: var(--radius-xl);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 32px;
}

.newsletter__title {
  font-size: var(--text-h2);
  font-weight: 600;
  margin-bottom: var(--space-md);
  color: var(--color-text-primary);
}

.newsletter__text {
  font-size: var(--text-body);
  color: var(--color-text-secondary);
  margin-bottom: var(--space-xl);
}

.newsletter__form {
  display: flex;
  gap: var(--space-sm);
  max-width: 400px;
  margin: 0 auto;
}

.newsletter__input {
  flex: 1;
  padding: 14px 20px;
  background: var(--color-surface-secondary);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  font-size: var(--text-small);
  color: var(--color-text-primary);
  transition: all var(--duration-fast) var(--ease-out);
}

.newsletter__input:focus {
  outline: none;
  border-color: var(--color-accent);
  box-shadow: 0 0 0 3px var(--color-accent-light);
}

.newsletter__input::placeholder {
  color: var(--color-text-tertiary);
}

/* ============================================
   FOOTER
   ============================================ */

.footer {
  background: var(--color-surface);
  border-top: 1px solid var(--color-border-light);
  padding: var(--space-3xl) 0 var(--space-xl);
  margin-top: var(--space-section);
}

.footer__inner {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: var(--space-xl);
}

.footer__brand {
  max-width: 300px;
}

.footer__logo {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  font-weight: 600;
  font-size: var(--text-h3);
  margin-bottom: var(--space-md);
  color: var(--color-text-primary);
}

.footer__logo-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  background: var(--color-accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 700;
}

.footer__description {
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
  margin-bottom: var(--space-lg);
}

.footer__social {
  display: flex;
  gap: var(--space-sm);
}

.footer__social-link {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-full);
  background: var(--color-surface-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-secondary);
  transition: all var(--duration-normal) var(--ease-out);
}

.footer__social-link:hover {
  background: var(--color-accent);
  color: white;
  transform: translateY(-4px);
  text-decoration: none;
}

.footer__heading {
  font-size: var(--text-small);
  font-weight: 600;
  color: var(--color-text-primary);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wide);
  margin-bottom: var(--space-lg);
}

.footer__links {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.footer__link {
  font-size: var(--text-small);
  color: var(--color-text-secondary);
  transition: all var(--duration-fast) var(--ease-out);
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
}

.footer__link:hover {
  color: var(--color-accent);
  padding-left: var(--space-xs);
  text-decoration: none;
}

.footer__bottom {
  margin-top: var(--space-3xl);
  padding-top: var(--space-xl);
  border-top: 1px solid var(--color-border-light);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--space-md);
}

.footer__copyright {
  font-size: var(--text-small);
  color: var(--color-text-tertiary);
}

.footer__bottom-links {
  display: flex;
  gap: var(--space-lg);
}

.footer__bottom-link {
  font-size: var(--text-small);
  color: var(--color-text-tertiary);
}

.footer__bottom-link:hover {
  color: var(--color-accent);
  text-decoration: none;
}

/* ============================================
   SCROLL ANIMATIONS
   ============================================ */

.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: all var(--duration-slower) var(--ease-out);
}

.reveal.revealed {
  opacity: 1;
  transform: translateY(0);
}

.stagger > * {
  opacity: 0;
  transform: translateY(20px);
  transition: all var(--duration-slow) var(--ease-out);
}

.stagger.revealed > *:nth-child(1) { transition-delay: 0s; opacity: 1; transform: translateY(0); }
.stagger.revealed > *:nth-child(2) { transition-delay: 0.1s; opacity: 1; transform: translateY(0); }
.stagger.revealed > *:nth-child(3) { transition-delay: 0.2s; opacity: 1; transform: translateY(0); }
.stagger.revealed > *:nth-child(4) { transition-delay: 0.3s; opacity: 1; transform: translateY(0); }
.stagger.revealed > *:nth-child(5) { transition-delay: 0.4s; opacity: 1; transform: translateY(0); }
.stagger.revealed > *:nth-child(6) { transition-delay: 0.5s; opacity: 1; transform: translateY(0); }

/* ============================================
   SCROLL PROGRESS
   ============================================ */

.scroll-progress {
  position: fixed;
  top: 0;
  left: 0;
  height: 3px;
  background: var(--color-accent-gradient);
  z-index: var(--z-toast);
  transform-origin: left;
  transform: scaleX(0);
  transition: transform 0.1s linear;
}

/* ============================================
   BACK TO TOP
   ============================================ */

.back-to-top {
  position: fixed;
  bottom: var(--space-xl);
  right: var(--space-xl);
  width: 52px;
  height: 52px;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--shadow-lg);
  opacity: 0;
  visibility: hidden;
  transform: translateY(20px);
  transition: all var(--duration-normal) var(--ease-out);
  z-index: var(--z-sticky);
  cursor: pointer;
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.back-to-top:hover {
  background: var(--color-accent);
  color: white;
  border-color: var(--color-accent);
  transform: translateY(-4px);
  text-decoration: none;
}

/* ============================================
   SEARCH OVERLAY
   ============================================ */

.search-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  z-index: var(--z-modal);
  opacity: 0;
  visibility: hidden;
  transition: all var(--duration-normal) var(--ease-out);
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 15vh;
}

.search-overlay.active {
  opacity: 1;
  visibility: visible;
}

.search-overlay__inner {
  width: 100%;
  max-width: 600px;
  padding: 0 var(--space-lg);
  transform: translateY(-30px);
  opacity: 0;
  transition: all var(--duration-normal) var(--ease-out) 0.1s;
}

.search-overlay.active .search-overlay__inner {
  transform: translateY(0);
  opacity: 1;
}

.search-overlay__input-wrap {
  position: relative;
}

.search-overlay__input {
  width: 100%;
  padding: 20px 60px 20px 24px;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-xl);
  font-size: var(--text-h3);
  color: var(--color-text-primary);
  transition: all var(--duration-fast) var(--ease-out);
}

.search-overlay__input:focus {
  outline: none;
  border-color: var(--color-accent);
  box-shadow: var(--shadow-glow);
}

.search-overlay__input::placeholder {
  color: var(--color-text-tertiary);
}

.search-overlay__icon {
  position: absolute;
  right: 20px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--color-text-tertiary);
}

.search-overlay__close {
  position: absolute;
  top: var(--space-xl);
  right: var(--space-xl);
  width: 48px;
  height: 48px;
  background: var(--color-surface);
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--duration-normal) var(--ease-out);
  cursor: pointer;
  border: none;
}

.search-overlay__close:hover {
  background: var(--color-accent);
  color: white;
  transform: rotate(90deg);
}

/* ============================================
   COMMENTS
   ============================================ */

.comments {
  max-width: var(--content-max);
  margin: 0 auto;
  padding: 0 var(--space-lg);
  margin-top: var(--space-3xl);
}

.comments__title {
  font-size: var(--text-h2);
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: var(--space-xl);
}

.comments__list {
  display: flex;
  flex-direction: column;
  gap: var(--space-xl);
}

.comment {
  display: flex;
  gap: var(--space-md);
}

.comment__avatar {
  width: 48px;
  height: 48px;
  border-radius: var(--radius-full);
  object-fit: cover;
  flex-shrink: 0;
}

.comment__content {
  flex: 1;
}

.comment__header {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  margin-bottom: var(--space-sm);
}

.comment__author {
  font-weight: 600;
  color: var(--color-text-primary);
}

.comment__date {
  font-size: var(--text-caption);
  color: var(--color-text-tertiary);
}

.comment__body {
  font-size: var(--text-body);
  color: var(--color-text-secondary);
  line-height: var(--leading-relaxed);
}

.comment__actions {
  display: flex;
  gap: var(--space-md);
  margin-top: var(--space-sm);
}

.comment__action {
  font-size: var(--text-small);
  color: var(--color-text-tertiary);
  transition: color var(--duration-fast) var(--ease-out);
}

.comment__action:hover {
  color: var(--color-accent);
  text-decoration: none;
}

/* ============================================
   RESPONSIVE
   ============================================ */

@media (max-width: 1024px) {
  .footer__inner {
    grid-template-columns: 1fr 1fr;
  }

  .featured-post {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  :root {
    --space-section: 80px;
    --nav-height: 64px;
  }

  .navbar__nav {
    display: none;
  }

  .menu-toggle {
    display: flex;
  }

  .hero__title {
    font-size: clamp(2.5rem, 10vw, 4rem);
  }

  .hero__actions {
    flex-direction: column;
    width: 100%;
  }

  .btn {
    width: 100%;
    justify-content: center;
  }

  .posts-grid {
    grid-template-columns: 1fr;
  }

  .footer__inner {
    grid-template-columns: 1fr;
    gap: var(--space-xl);
  }

  .footer__brand {
    max-width: 100%;
  }

  .footer__bottom {
    flex-direction: column;
    text-align: center;
  }

  .newsletter__form {
    flex-direction: column;
  }

  .newsletter {
    padding: var(--space-xl);
  }

  .back-to-top {
    bottom: var(--space-lg);
    right: var(--space-lg);
    width: 48px;
    height: 48px;
  }
}

@media (max-width: 480px) {
  .container {
    padding: 0 var(--space-md);
  }

  .hero__inner {
    padding: var(--space-3xl) var(--space-md);
  }

  .blog-post__content {
    padding: var(--space-md);
  }
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .reveal, .stagger > * {
    opacity: 1;
    transform: none;
  }
}

@media print {
  .navbar, .menu-overlay, .back-to-top, .scroll-progress, .footer__social {
    display: none !important;
  }

  body {
    background: white;
    color: black;
  }
}


/* ============================================
   PIXELOS GRADIENTS & MONOGRAM FALLBACKS
   ============================================ */
.blog-post__image--gradient {
  background: linear-gradient(135deg, #4285f4, #34a853, #fabc05, #ea4335);
  background-size: 300% 300%;
  animation: monetMesh 12s ease infinite;
  display: flex;
  align-items: center;
  justify-content: center;
  aspect-ratio: 16 / 10;
  position: relative;
  overflow: hidden;
}

[data-theme="dark"] .blog-post__image--gradient {
  background: linear-gradient(135deg, #1a73e8, #1557b0, #18191e, #1f2026);
  background-size: 300% 300%;
}

.featured-post__image--gradient {
  background: linear-gradient(135deg, #4285f4, #8ab4f8, #c2e7ff);
  background-size: 300% 300%;
  animation: monetMesh 12s ease infinite;
  display: flex;
  align-items: center;
  justify-content: center;
  aspect-ratio: 4 / 3;
  position: relative;
  overflow: hidden;
}

[data-theme="dark"] .featured-post__image--gradient {
  background: linear-gradient(135deg, #18191e, #1a73e8, #2d2e30);
  background-size: 300% 300%;
}

@keyframes monetMesh {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.blog-post__monogram {
  font-size: 4rem;
  font-weight: 800;
  color: #ffffff;
  text-shadow: 0 4px 12px rgba(0, 0, 0, 0.15);
  user-select: none;
  font-family: var(--font);
}

.featured-post__monogram {
  font-size: 6rem;
  font-weight: 800;
  color: #ffffff;
  text-shadow: 0 6px 18px rgba(0, 0, 0, 0.2);
  user-select: none;
  font-family: var(--font);
}

.blog-post__image--gradient .blog-post__category {
  z-index: 2;
}

.navbar__logo-icon {
  background: linear-gradient(135deg, #1a73e8 0%, #34a853 100%) !important;
}

.btn--primary {
  box-shadow: 0 4px 15px rgba(26, 115, 232, 0.2) !important;
}

.btn--primary:hover {
  box-shadow: 0 8px 25px rgba(26, 115, 232, 0.3) !important;
}

.blog-post {
  border-radius: var(--radius-xl) !important;
  box-shadow: var(--shadow-sm) !important;
}

.blog-post:hover {
  box-shadow: var(--shadow-lg) !important;
}

.featured-post {
  border-radius: var(--radius-xl2) !important;
  box-shadow: var(--shadow-sm) !important;
}

.featured-post:hover {
  box-shadow: var(--shadow-xl) !important;
}

body.script:
//
/**
 * AiCoN Blog Theme - JavaScript
 * Version: 1.0.0
 */

// Theme Management
(function() {
  const storageKey = 'aicon-theme';
  const savedTheme = localStorage.getItem(storageKey);
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

  function setTheme(isDark) {
    document.body.setAttribute('data-theme', isDark ? 'dark' : 'light');
    localStorage.setItem(storageKey, isDark ? 'dark' : 'light');
  }

  if (savedTheme) {
    setTheme(savedTheme === 'dark');
  } else {
    setTheme(prefersDark);
  }

  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', function(e) {
    if (!localStorage.getItem(storageKey)) {
      setTheme(e.matches);
    }
  });

  var themeToggle = document.getElementById('theme-toggle');
  if (themeToggle) {
    themeToggle.addEventListener('click', function() {
      var currentTheme = document.body.getAttribute('data-theme');
      setTheme(currentTheme !== 'dark');
    });
  }
})();

// Mobile Navigation
(function() {
  var menuToggle = document.getElementById('menu-toggle');
  var menuOverlay = document.getElementById('menu-overlay');

  if (menuToggle && menuOverlay) {
    menuToggle.addEventListener('click', function() {
      var isOpen = menuOverlay.classList.toggle('active');
      menuToggle.classList.toggle('active', isOpen);
      menuToggle.setAttribute('aria-expanded', isOpen);
      document.body.style.overflow = isOpen ? 'hidden' : '';
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && menuOverlay.classList.contains('active')) {
        menuOverlay.classList.remove('active');
        menuToggle.classList.remove('active');
        menuToggle.setAttribute('aria-expanded', 'false');
        document.body.style.overflow = '';
      }
    });
  }
})();

// Search Overlay
(function() {
  var searchOverlay = document.getElementById('search-overlay');
  var searchClose = document.getElementById('search-close');
  var searchToggles = document.querySelectorAll('[data-search-toggle]');

  if (searchOverlay) {
    searchToggles.forEach(function(btn) {
      btn.addEventListener('click', function() {
        searchOverlay.classList.add('active');
        document.body.style.overflow = 'hidden';
        searchOverlay.querySelector('input').focus();
      });
    });

    if (searchClose) {
      searchClose.addEventListener('click', function() {
        searchOverlay.classList.remove('active');
        document.body.style.overflow = '';
      });
    }

    searchOverlay.addEventListener('click', function(e) {
      if (e.target === searchOverlay) {
        searchOverlay.classList.remove('active');
        document.body.style.overflow = '';
      }
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && searchOverlay.classList.contains('active')) {
        searchOverlay.classList.remove('active');
        document.body.style.overflow = '';
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        searchOverlay.classList.toggle('active');
        document.body.style.overflow = searchOverlay.classList.contains('active') ? 'hidden' : '';
      }
    });
  }
})();

// Scroll Progress
(function() {
  var progressBar = document.querySelector('.scroll-progress');
  if (progressBar) {
    window.addEventListener('scroll', function() {
      var scrollTop = window.scrollY || document.documentElement.scrollTop;
      var docHeight = document.documentElement.scrollHeight - window.innerHeight;
      var progress = docHeight > 0 ? scrollTop / docHeight : 0;
      progressBar.style.transform = 'scaleX(' + progress + ')';
    }, { passive: true });
  }
})();

// Back to Top
(function() {
  var backToTop = document.getElementById('back-to-top');
  if (backToTop) {
    backToTop.addEventListener('click', function(e) {
      e.preventDefault();
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });

    window.addEventListener('scroll', function() {
      if (window.scrollY > 500) {
        backToTop.classList.add('visible');
      } else {
        backToTop.classList.remove('visible');
      }
    }, { passive: true });
  }
})();

// Scroll Animations
(function() {
  if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
    document.querySelectorAll('.reveal, .stagger').forEach(function(el) {
      el.classList.add('revealed');
    });
    return;
  }

  var observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting) {
        entry.target.classList.add('revealed');
      }
    });
  }, { rootMargin: '0px 0px -100px 0px', threshold: 0.1 });

  document.querySelectorAll('.reveal, .stagger').forEach(function(el) {
    observer.observe(el);
  });
})();

// Navbar Scroll
(function() {
  var navbar = document.querySelector('.navbar');
  if (navbar) {
    window.addEventListener('scroll', function() {
      if (window.scrollY > 50) {
        navbar.classList.add('scrolled');
      } else {
        navbar.classList.remove('scrolled');
      }
    }, { passive: true });
  }
})();

// Current Year
(function() {
  var yearEl = document.getElementById('current-year');
  if (yearEl) {
    yearEl.textContent = new Date().getFullYear();
  }
})();

// Button Ripple
document.querySelectorAll('.btn').forEach(function(btn) {
  btn.addEventListener('click', function(e) {
    var rect = btn.getBoundingClientRect();
    var x = e.clientX - rect.left;
    var y = e.clientY - rect.top;

    var ripple = document.createElement('span');
    ripple.className = 'btn__ripple';
    ripple.style.left = x + 'px';
    ripple.style.top = y + 'px';

    btn.appendChild(ripple);

    setTimeout(function() {
      ripple.remove();
    }, 600);
  });
});

// Post Monograms fallback generator
(function() {
  document.querySelectorAll('.blog-post__monogram, .featured-post__monogram').forEach(function(el) {
    var text = el.textContent.trim();
    if (text.length > 0) {
      el.textContent = text.charAt(0).toUpperCase();
    }
  });
})();

//
